// WindowWorld Service Worker — manual push/offline layer
// NOTE: This file handles push notifications and offline fallback ONLY.
// The primary service worker (Workbox, auto-generated by vite-plugin-pwa)
// is dist/sw.js. This file is imported into it via importScripts('/sw-push.js').
// DO NOT register this file directly — vite-plugin-pwa handles registration.
//
// Cache busting: the Workbox SW uses a cacheId = `ww-${BUILD_TIME}` that
// changes on every build, so users always get fresh JS after a deploy.

// ── Push Notifications ──────────────────────────────────────────────────────
self.addEventListener('push', (event) => {
  let data = {
    title: 'WindowWorld',
    body: 'You have a new notification',
    icon: '/icon-192.png',
    badge: '/icon-192.png',
  };

  try {
    const payload = event.data?.json();
    data = { ...data, ...payload };
  } catch (e) {}

  event.waitUntil(
    self.registration.showNotification(data.title, {
      body: data.body,
      icon: data.icon,
      badge: data.badge,
      vibrate: [100, 50, 100],
      data: { url: data.url || '/dashboard' },
      actions: [
        { action: 'open',    title: 'Open App' },
        { action: 'dismiss', title: 'Dismiss'  },
      ],
    })
  );
});

// ── Notification click: navigate to relevant page ───────────────────────────
self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  if (event.action === 'dismiss') return;

  const targetUrl = event.notification.data?.url || '/dashboard';

  event.waitUntil(
    self.clients.matchAll({ type: 'window' }).then((clients) => {
      const existing = clients.find((c) => c.url.includes(self.location.origin));
      if (existing) { existing.focus(); existing.navigate(targetUrl); }
      else self.clients.openWindow(targetUrl);
    })
  );
});

// ── Background Sync (offline note saves) ────────────────────────────────────
self.addEventListener('sync', (event) => {
  if (event.tag === 'sync-pending-notes') {
    event.waitUntil(syncPendingNotes());
  }
});

async function syncPendingNotes() {
  console.log('[SW] Syncing pending notes...');
}
